	Status            SandboxStatus `json:"status,omitempty"`
}

func (in *Sandbox) GetObjectKind() schema.ObjectKind {
	return &in.TypeMeta
}

func (in *Sandbox) DeepCopyObject() runtime.Object {
	if in == nil {
		return nil
	}
	out := new(Sandbox)
	in.DeepCopyInto(out)
