	out.TypeMeta = in.TypeMeta
	in.ObjectMeta.DeepCopyInto(&out.ObjectMeta)
}

type SandboxSpec struct {
	SessionID    string            `json:"sessionID,omitempty"`
	SandboxType  string            `json:"sandboxType,omitempty"`
