package agentd

import (
	"context"
	"time"

	apiErrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/runtime"
	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/log"

	agentcube "github.com/volcano-sh/agentcube/pkg/workloadmanager"
	v1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
)

const (
	LastActivityAnnotationKey = "last-activity-time"
)

type Reconciler struct {
	client.Client
	Scheme   *runtime.Scheme
	watchers map[string]chan struct{}
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	log := log.FromContext(ctx)
	log.Info("Reconciling Sandbox")

	sandbox := &v1alpha1.Sandbox{}
	if err := r.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if apiErrors.IsNotFound(err) {
			log.Info("Sandbox not found, skipping")
			return ctrl.Result{}, nil
		}
		log.Error(err, "Failed to get Sandbox")
		return ctrl.Result{}, err
	}

	annotations := sandbox.GetAnnotations()
	if annotations == nil {
		log.Info("No annotations found on Sandbox, skipping")
		return ctrl.Result{}, nil
	}

	lastActivityStr, exists := annotations[agentcube.LastActivityAnnotationKey]
	if !exists || lastActivityStr == "" {
		log.Info("No last activity annotation found, skipping")
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		log.Error(err, "Failed to parse last activity timestamp, requeueing")
		return ctrl.Result{RequeueAfter: 30 * time.Second}, nil
	}

	expirationTime := lastActivity.Add(15 * time.Minute)

	if time.Now().After(expirationTime) {
		log.Info("Sandbox expired, deleting", "expirationTime", expirationTime)
		if err := r.Delete(ctx, sandbox); err != nil {
			if apiErrors.IsNotFound(err) {
				return ctrl.Result{}, nil
			}
			log.Error(err, "Failed to delete Sandbox")
			return ctrl.Result{}, err
		}
		return ctrl.Result{}, nil
	}

	log.Info("Sandbox not expired, requeueing", "expirationTime", expirationTime)
	return ctrl.Result{RequeueAfter: time.Until(expirationTime)}, nil
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&v1alpha1.Sandbox{}).
		Complete(r)
}

