package main

import (
	"flag"
	"os"
	"os/signal"
	"syscall"

	"github.com/volcano-sh/agentcube/pkg/agentd"
	"k8s.io/klog/v2"
	ctrl "sigs.k8s.io/controller-runtime"
)

func main() {
	var (
		metricsAddr          string
		healthProbeAddr      string
		enableLeaderElection bool
	)

	flag.StringVar(&metricsAddr, "metrics-addr", ":8080", "The address the metric endpoint binds to")
	flag.StringVar(&healthProbeAddr, "health-probe-addr", ":8081", "The address the health probe endpoint binds to")
	flag.BoolVar(&enableLeaderElection, "enable-leader-election", false, "Enable leader election")

	klog.InitFlags(nil)
	flag.Parse()

	mgr, err := ctrl.NewManager(ctrl.GetConfigOrDie(), ctrl.Options{
		Scheme:                 nil,
		MetricsBindAddress:     metricsAddr,
		HealthProbeBindAddress: healthProbeAddr,
		LeaderElection:         enableLeaderElection,
	})
	if err != nil {
		klog.Fatalf("Unable to create manager: %v", err)
	}

	if err := agentd.Setup(mgr); err != nil {
		klog.Fatalf("Unable to create controller: %v", err)
	}

	klog.Info("Starting agentd controller...")

	ctx := ctrl.SetupSignalHandler()

	if err := mgr.Start(ctx); err != nil {
		klog.Fatalf("Problem running manager: %v", err)
	}

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)
	<-sigChan
	klog.Info("Shutting down agentd controller...")
}

