const SessionExpirationTimeout = 15 * time.Minute

type Reconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	logger := ctrl.LoggerFrom(ctx)

	sandbox := &sandboxv1alpha1.Sandbox{}
	err := r.Get(ctx, req.NamespacedName, sandbox)
	if err != nil {
		if errors.IsNotFound(err) {
			return ctrl.Result{}, nil
		}
		return ctrl.Result{}, err
	}

	annotationValue, exists := sandbox.Annotations[workloadmanager.LastActivityAnnotationKey]
	if !exists || annotationValue == "" {
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, annotationValue)
	if err != nil {
		logger.Error(err, "failed to parse last activity annotation", "value", annotationValue)
		return ctrl.Result{RequeueAfter: 30 * time.Second}, nil
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expirationTime) {
		logger.Info("deleting expired sandbox", "name", req.Name, "namespace", req.Namespace)
		if err := r.Delete(ctx, sandbox); err != nil {
			if errors.IsNotFound(err) {
				return ctrl.Result{}, nil
			}
			return ctrl.Result{}, err
		}
		return ctrl.Result{}, nil
	}

	return ctrl.Result{RequeueAfter: time.Until(expirationTime)}, nil
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&sandboxv1alpha1.Sandbox{}).
		Complete(r)
}

