	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/client/fake"

	"github.com/volcano-sh/agentcube/pkg/apis/runtime/v1alpha1"
	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
)

func TestReconcile(t *testing.T) {
	scheme := runtime.NewScheme()
	_ = v1alpha1.AddToScheme(scheme)

	now := time.Now()

	tests := []struct {
		name                       string
		sandbox                    *v1alpha1.Sandbox
		expectedRequeueAfter       time.Duration
		expectedRequeueAfterExists bool
	}{
		{
			name: "sandbox not found",
			sandbox: &v1alpha1.Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Name:      "test-sandbox",
					Namespace: "default",
				},
			},
		},
		{
			name: "no annotation - no requeue",
			sandbox: &v1alpha1.Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Name:        "test-sandbox",
					Namespace:   "default",
					Annotations: map[string]string{},
				},
			},
		},
		{
			name: "invalid annotation - requeue after 30s",
			sandbox: &v1alpha1.Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Name:      "test-sandbox",
					Namespace: "default",
					Annotations: map[string]string{
						workloadmanager.LastActivityAnnotationKey: "invalid-time",
					},
				},
			},
			expectedRequeueAfter:       30 * time.Second,
			expectedRequeueAfterExists: true,
		},
		{
			name: "expired sandbox - should delete",
			sandbox: &v1alpha1.Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Name:      "test-sandbox",
					Namespace: "default",
					Annotations: map[string]string{
						workloadmanager.LastActivityAnnotationKey: now.Add(-20 * time.Minute).Format(time.RFC3339),
					},
				},
			},
		},
		{
			name: "active sandbox - requeue after",
			sandbox: &v1alpha1.Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Name:      "test-sandbox",
					Namespace: "default",
					Annotations: map[string]string{
						workloadmanager.LastActivityAnnotationKey: now.Format(time.RFC3339),
					},
				},
			},
			expectedRequeueAfterExists: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			Objs := []client.Object{tt.sandbox}
			if tt.name == "sandbox not found" {
				Objs = []client.Object{}
			}
			fakeClient := fake.NewClientBuilder().WithScheme(scheme).WithObjects(Objs...).Build()

			r := &Reconciler{
				Client: fakeClient,
				Scheme: scheme,
			}

			req := ctrl.Request{
				NamespacedName: types.NamespacedName{
					Name:      tt.sandbox.Name,
					Namespace: tt.sandbox.Namespace,
				},
			}

			result, err := r.Reconcile(context.Background(), req)
			if err != nil {
				t.Errorf("Reconcile() error = %v", err)
				return
			}

			if tt.expectedRequeueAfterExists {
				if result.RequeueAfter == 0 {
					t.Errorf("Reconcile() expected RequeueAfter to be set")
				}
			} else if result.RequeueAfter != 0 {
				t.Errorf("Reconcile() expected RequeueAfter to be 0, got %v", result.RequeueAfter)
			}
		})
	}
}

