package store

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func (v *valkeyStore) sessionKey(sessionID string) string {
	return v.sessionPrefix + sessionID
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	result := v.cli.Do(ctx, v.cli.B().Ping().Build())
	val, err := result.ToString()
	if err != nil {
		return err
	}
	if val != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", val)
	}
	return nil
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	result := v.cli.Do(ctx, v.cli.B().Get().Key(v.sessionKey(sessionID)).Build())
	val, err := result.ToString()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}
	var info types.SandboxInfo
	if err := json.Unmarshal([]byte(val), &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return fmt.Errorf("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return fmt.Errorf("ExpiresAt is zero")
	}

	keyStr := v.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	cmds := []valkey.Completed{
		v.cli.B().Setnx().Key(keyStr).Value(string(data)).Build(),
		v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember().ScoreMember(float64(sandboxStore.ExpiresAt.Unix()), sandboxStore.SessionID).Build(),
		v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(float64(time.Now().Unix()), sandboxStore.SessionID).Build(),
	}
	results := v.cli.DoMulti(ctx, cmds...)
	for _, r := range results {
		if err := r.Error(); err != nil {
			return err
		}
	}
	return nil
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	keyStr := v.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}
	result := v.cli.Do(ctx, v.cli.B().Set().Key(keyStr).Value(string(data)).Nx().Build())
	s, err := result.ToString()
	if err != nil {
		return err
	}
	if s != "OK" {
		return ErrKeyNotExists
	}
	return nil
}

func (v *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	keyStr := v.sessionKey(sessionID)
	cmds := []valkey.Completed{
		v.cli.B().Del().Key(keyStr).Build(),
		v.cli.B().Zrem().Key(v.expiryIndexKey).Members().Member(sessionID).Build(),
		v.cli.B().Zrem().Key(v.lastActivityIndexKey).Members().Member(sessionID).Build(),
	}
	results := v.cli.DoMulti(ctx, cmds...)
	for _, r := range results {
		if err := r.Error(); err != nil {
			return err
		}
	}
	return nil
}

func (v *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	result := v.cli.Do(ctx, v.cli.B().Zrangebyscore().Key(v.expiryIndexKey).
		Min("-inf").
		Max(fmt.Sprintf("%d", before.Unix())).
		Limit(0, limit).
		Build())
	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}
	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	result := v.cli.Do(ctx, v.cli.B().Zrangebyscore().Key(v.lastActivityIndexKey).
		Min("-inf").
		Max(fmt.Sprintf("%d", before.Unix())).
		Limit(0, limit).
		Build())
	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}
	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}
	keys := make([]valkey.Completed, len(sessionIDs))
	for i, sid := range sessionIDs {
		keys[i] = v.cli.B().Get().Key(v.sessionKey(sid)).Build()
	}
	results := v.cli.DoMulti(ctx, keys...)

	var result []*types.SandboxInfo
	for _, res := range results {
		val, err := res.ToString()
		if err != nil {
			continue
		}
		if valkey.IsValkeyNil(err) {
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &info); err != nil {
			continue
		}
		result = append(result, &info)
	}
	return result, nil
}

func (v *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("session id is empty")
	}
	if at.IsZero() {
		at = time.Now()
	}
	keyStr := v.sessionKey(sessionID)
	exists, err := v.cli.Do(ctx, v.cli.B().Exists().Key(keyStr).Build()).AsInt64()
	if err != nil {
		return err
	}
	if exists != 1 {
		return ErrNotFound
	}
	result := v.cli.Do(ctx, v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build())
	return result.Error()
}

func (v *valkeyStore) Close() error {
	v.cli.Close()
	return nil
}

